fn route_request(req: &Request) -> BackendConfig {
    let path = req.get_path();

    if path.starts_with("/api/") || path.starts_with("/v1/") || path.starts_with("/v2/") {
        BackendConfig::api()
    } else if path.starts_with("/static/")
        || path.starts_with("/assets/")
        || path.starts_with("/images/")
        || path.ends_with(".css")
        || path.ends_with(".js")
        || path.ends_with(".png")
        || path.ends_with(".jpg")
        || path.ends_with(".gif")
        || path.ends_with(".svg")
        || path.ends_with(".woff2")
    {
        BackendConfig::secondary()
    } else {
        BackendConfig::primary()
    }
}

fn send_to_backend(mut req: Request, config: &BackendConfig) -> Result<Response, Error> {
    req.set_header(header::HOST, config.host);

    if config.use_tls {
        req.set_header("X-Forwarded-Proto", "https");
    }

    req.set_header("X-Backend-Name", config.name);
    req.set_header("X-Backend-Host", config.host);
    req.set_header("X-Backend-Port", config.port.to_string());

    let backend = Backend::from_name(config.name)?;

    match req.send(backend) {
        Ok(resp) => Ok(resp),
        Err(e) => {
            eprintln!(
                "Error sending request to backend {}: {:?}",
                config.name, e
            );
            Ok(Response::from_status(StatusCode::BAD_GATEWAY)
                .with_content_type(mime::TEXT_PLAIN_UTF_8)
                .with_body(format!(
                    "Backend {} is unavailable. Error: {:?}",
                    config.name, e
                )))
        }
    }
}

fn handle_health_check() -> Response {
    Response::from_status(StatusCode::OK)
        .with_content_type(mime::APPLICATION_JSON)
        .with_body(r#"{"status":"healthy","service":"edge-router"}"#)
}

fn handle_cors_preflight(req: &Request) -> Response {
    let origin = req
        .get_header_str("Origin")
        .unwrap_or("*")
        .to_string();

    Response::from_status(StatusCode::NO_CONTENT)
        .with_header("Access-Control-Allow-Origin", origin)
        .with_header(
            "Access-Control-Allow-Methods",
            "GET, POST, PUT, DELETE, PATCH, OPTIONS",
        )
        .with_header(
            "Access-Control-Allow-Headers",
            "Content-Type, Authorization, X-Requested-With",
        )
        .with_header("Access-Control-Max-Age", "86400")
}

fn add_security_headers(mut resp: Response) -> Response {
    resp.set_header("X-Content-Type-Options", "nosniff");
    resp.set_header("X-Frame-Options", "DENY");
    resp.set_header("X-XSS-Protection", "1; mode=block");
    resp.set_header("Referrer-Policy", "strict-origin-when-cross-origin");
    resp.set_header(
        "Strict-Transport-Security",
        "max-age=31536000; includeSubDomains; preload",
    );
    resp
}

fn add_cors_headers(mut resp: Response, req: &Request) -> Response {
    if let Some(origin) = req.get_header_str("Origin") {
        resp.set_header("Access-Control-Allow-Origin", origin);
        resp.set_header("Access-Control-Allow-Credentials", "true");
        resp.set_header(
            "Access-Control-Expose-Headers",
            "Content-Length, X-Request-Id",
        );
    }
    resp
}

#[fastly::main]
fn main(req: Request) -> Result<Response, Error> {
    let client_ip = req
        .get_client_ip_addr()
        .map(|ip| ip.to_string())
        .unwrap_or_else(|| "unknown".to_string());

    println!(
        "Incoming request: {} {} from {}",
        req.get_method(),
        req.get_path(),
        client_ip
    );

    // Handle health check endpoint
    if req.get_path() == "/health" || req.get_path() == "/__health" {
        return Ok(handle_health_check());
    }

    // Handle CORS preflight requests
    if req.get_method() == Method::OPTIONS {
        return Ok(handle_cors_preflight(&req));
    }

    // Determine which backend to route to
    let backend_config = route_request(&req);

    println!(
        "Routing to backend: {} ({}:{})",
        backend_config.name, backend_config.host, backend_config.port
    );

    // Send request to the appropriate backend
    let mut resp = send_to_backend(req.clone_without_body(), &backend_config)?;

    // Add security headers
    resp = add_security_headers(resp);

    // Add CORS headers if needed
    resp = add_cors_headers(resp, &req);

    // Add custom headers for debugging
    resp.set_header("X-Served-By", "fastly-edge-router");
    resp.set_header("X-Backend-Used", backend_config.name);

    // Add cache control headers for static assets
    if backend_config.name == BACKEND_SECONDARY {
        if !resp.contains_header(header::CACHE_CONTROL) {
            resp.set_header(header::CACHE_CONTROL, "public, max-age=31536000, immutable");
        }
    }

    Ok(resp)
}